import { ChevronLeft, User, LogOut, Save, Database, Globe, Disc } from 'lucide-react';

// Icône Scie Circulaire personnalisée en SVG
const CircularSawIcon = ({ className }) => (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}>
    <circle cx="12" cy="12" r="10" />
    <circle cx="12" cy="12" r="3" />
    <path d="M12 2v4" />
    <path d="M12 18v4" />
    <path d="M4.93 4.93l2.83 2.83" />
    <path d="M16.24 16.24l2.83 2.83" />
    <path d="M2 12h4" />
    <path d="M18 12h4" />
    <path d="M4.93 19.07l2.83-2.83" />
    <path d="M16.24 7.76l2.83-2.83" />
  </svg>
);

export default function Header({ 
  title, 
  subtitle, 
  onBack, 
  user, 
  onLogout, 
  steps, 
  onSave, 
  saving, 
  saveMsg,
  lang,
  onToggleLang
}) {
  return (
    <header className="sticky top-0 z-50 w-full bg-[#0a0a0a]/90 backdrop-blur-xl border-b border-white/5 shadow-lg shadow-black/20">
      <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">

        {/* GAUCHE: Retour + Titre + Scie */}
        <div className="flex items-center gap-4 flex-1 min-w-0">
          {onBack && (
            <button 
              onClick={onBack}
              className="p-2 -ml-2 rounded-lg text-slate-400 hover:text-white hover:bg-white/5 transition-all"
            >
              <ChevronLeft className="w-6 h-6" />
            </button>
          )}

          <div className="flex items-center gap-3 min-w-0 cursor-pointer" onClick={() => !onBack && window.location.reload()}>
            <div className="w-9 h-9 bg-gradient-to-br from-orange-500 to-red-600 rounded-xl flex items-center justify-center shadow-lg shadow-orange-900/30 flex-shrink-0 transform hover:rotate-45 transition-transform duration-500">
              <CircularSawIcon className="w-5 h-5 text-white" />
            </div>
            <div className="min-w-0">
              <h1 className="text-lg font-black text-white leading-tight truncate">PanelCut <span className="text-orange-500">Pro</span></h1>
              {subtitle && <p className="text-[10px] text-slate-400 font-medium uppercase tracking-wider truncate">{subtitle}</p>}
            </div>
          </div>
        </div>

        {/* CENTRE: STEPPER */}
        {steps && steps.length > 0 && (
          <div className="hidden md:flex items-center gap-2 absolute left-1/2 -translate-x-1/2 bg-[#0f0f0f] px-4 py-1.5 rounded-full border border-white/5">
            {steps.map((step, idx) => (
              <div key={idx} className="flex items-center">
                <div className={`flex items-center gap-2 px-3 py-1 rounded-full text-[10px] font-bold uppercase transition-all ${
                  step.active ? 'bg-orange-500 text-white shadow-lg' : 'bg-transparent text-slate-500'
                }`}>
                  <span className={`w-4 h-4 rounded-full flex items-center justify-center text-[9px] ${step.active ? 'bg-white/20' : 'bg-white/10 border'}`}>
                    {idx + 1}
                  </span>
                  <span className="hidden lg:inline">{step.label}</span>
                </div>
                {idx < steps.length - 1 && (
                  <div className={`w-6 h-0.5 mx-1 rounded-full ${step.active ? 'bg-orange-500/50' : 'bg-white/5'}`}></div>
                )}
              </div>
            ))}
          </div>
        )}

        {/* DROITE: Sauvegarde + Langue + Utilisateur */}
        <div className="flex items-center gap-2 sm:gap-3 flex-1 justify-end">

          {/* Message de sauvegarde */}
          {(saveMsg || saving) && (
            <div className={`hidden sm:flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-bold ${
              saveMsg?.includes('✓') ? 'bg-green-500/10 text-green-400 border border-green-500/20' : 'bg-blue-500/10 text-blue-400 border border-blue-500/20'
            }`}>
              {saving ? <Database className="w-3.5 h-3.5 animate-spin" /> : <Save className="w-3.5 h-3.5" />}
              <span>{saving ? '...' : saveMsg}</span>
            </div>
          )}

          {/* BOUTON DISQUETTE (Sauvegarder) */}
          {onSave && !saving && (
            <button 
              onClick={onSave}
              className="group relative flex items-center justify-center w-10 h-10 bg-white/10 hover:bg-orange-500 text-slate-300 hover:text-white rounded-lg transition-all duration-300 border border-white/10 hover:border-orange-500 hover:shadow-lg hover:shadow-orange-900/30 transform hover:-translate-y-0.5"
              title="Sauvegarder le projet"
            >
              <Disc className="w-5 h-5 group-hover:scale-110 transition-transform" />
              <span className="absolute -bottom-8 scale-0 group-hover:scale-100 bg-black text-white text-[10px] px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-all whitespace-nowrap pointer-events-none">
                Sauvegarder
              </span>
            </button>
          )}

          {/* BOUTON LANGUE */}
          {onToggleLang && (
            <button 
              onClick={onToggleLang}
              className="group relative flex items-center justify-center w-10 h-10 bg-white/10 hover:bg-blue-500 text-slate-300 hover:text-white rounded-lg transition-all duration-300 border border-white/10 hover:border-blue-500 hover:shadow-lg hover:shadow-blue-900/30 transform hover:-translate-y-0.5"
              title="Changer de langue"
            >
              <Globe className="w-5 h-5 group-hover:rotate-12 transition-transform" />
              <span className="absolute text-[9px] font-bold ml-3">{lang === 'fr' ? 'EN' : 'FR'}</span>
            </button>
          )}

          {/* Séparateur */}
          {(onSave || onToggleLang || user) && <div className="w-px h-6 bg-white/10 hidden sm:block"></div>}

          {/* Profil Utilisateur */}
          {user ? (
            <div className="group relative flex items-center gap-2 bg-white/5 hover:bg-white/10 border border-white/5 rounded-full pl-1 pr-3 py-1 transition-all cursor-pointer">
              <div className="w-7 h-7 bg-gradient-to-tr from-blue-500 to-purple-600 rounded-full flex items-center justify-center text-xs font-bold text-white shadow-inner ring-2 ring-white/10 group-hover:ring-orange-500/50">
                {user.email ? user.email[0].toUpperCase() : 'U'}
              </div>
              <span className="text-xs font-medium text-slate-300 group-hover:text-white max-w-[100px] truncate hidden sm:inline">
                {user.email?.split('@')[0]}
              </span>
              {onLogout && (
                <button 
                  onClick={onLogout}
                  className="ml-1 p-1.5 text-slate-500 hover:text-red-400 hover:bg-red-500/10 rounded-full transition-colors opacity-0 group-hover:opacity-100"
                  title="Déconnexion"
                >
                  <LogOut className="w-3.5 h-3.5" />
                </button>
              )}
            </div>
          ) : (
             <div className="w-8 h-8 bg-white/5 rounded-full flex items-center justify-center border border-white/5">
               <User className="w-4 h-4 text-slate-500" />
             </div>
          )}
        </div>
      </div>
    </header>
  );
}
